VALUES
  ('dietitian-moex-08734', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '乙醯輔酶A羧化酶（acetyl-CoA carboxylase）的異位效應活化子（allosteric activator）為下列何者？', '["CO，因為它是乙醯輔酶A羧化酶的受質 2", "丙二醯輔酶A（malonyl-CoA），因為它是乙醯輔酶A羧化酶催化反應的產物", "檸檬酸（citrate），因為細胞質內的檸檬酸經分解後可以產生供脂肪酸生合成的乙醯輔酶A", "棕櫚醯輔酶A（palmitoyl-CoA），因為它是一種回饋性抑制物（feedback inhibitor）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08735', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '脂肪細胞進行脂解作用（lipolysis）的步驟包括下列何者？', '["利用ATP磷酸化甘油", "利用ADP活化三酸甘油酯脂解酶（triglyceride lipase）", "利用脂解酶磷酸酶（lipase phosphatase）活化激素敏感性脂解酶（hormone-sensitive lipase）", "利用cAMP依賴性蛋白激酶（cAMP-dependent protein kinase）活化激素敏感性脂解酶（hormone-sensitive lipase）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08736', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '當肝細胞粒線體中乙醯輔酶A（acetyl-CoA）之含量急速增加、但粒線體中之草醋酸（oxaloacetate）與蘋 果酸（malate）的含量卻很低時，則乙醯輔酶 A（acetyl-CoA）中之乙醯基將用於進行下列何種生合成反 應？', '["用於生合成脂肪酸（fatty acid）與膽固醇（cholesterol）", "用於生合成酮體（ketone bodies）", "用於生合成葡萄糖", "用於生合成肝醣"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08737', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '生合成脂肪酸時需要使用二氧化碳或碳酸氫根離子（HCO-），其原因為何？ 3', '["碳酸氫根離子（HCO-）可改變酵素的構形（conformation），是脂肪酸生合成酵素的“正效應物（positive 3 effector）", "HCO-/ HCO緩衝液系統可提供脂肪酸生合成酵素最適的pH值", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08738', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '2 3', '["二氧化碳與乙醯輔酶A（acetyl-CoA）形成的丙二醯輔酶A（malonyl-CoA）是脂肪酸生合成反應的中 間產物", "二氧化碳能提供厭氧環境（anaerobic environment），可避免位於酵素活化中心之sulfurhydryl group進 行氧化", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08739', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '果糖-6-磷酸（fructose-6-phosphate）可調節磷酸果糖激酶-2（phosphofructokinase-2）和果糖-2,6-二磷 酸酶（fructose-2,6-bisphosphatase）二者酵素活性，即果糖-6-磷酸可分別提高和降低磷酸果糖激酶-2 和果糖-2,6-二磷酸酶的活性。此調節機制稱為：', '["substrate level control", "allosteric regulation", "compartmentalized control", "hormonal regulation"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08740', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '戊糖磷酸途徑（pentose phosphate pathway）中那一個酵素所催化的反應，為此代謝途徑的速率調節步驟？', '["glucose-6-phosphate dehydrogenase", "transketolase", "6-phosphogluconate dehydrogenase", "transaldolase"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08741', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '糖質新生作用（gluconeogenesis）主要在肝臟與腎皮質中進行，乃因下列那一種酵素不存在於腦與肌肉等 其他組織器官中？', '["丙酮酸羧化酶（pyruvate carboxylase）", "磷酸烯醇丙酮酸羧化激酶（phosphoenolpyruvate carboxykinase）", "果糖-1,6-二磷酸酶（fructose-1,6-bisphosphatase）", "葡萄糖-6-磷酸酶（glucose-6-phosphatase）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08742', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '若以Fischer Projection理論分析monosaccharide結構時，D-glucose和D-mannose二者互為：', '["enantiomers", "chiral centers", "epimers", "configurations"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "515efe52e2f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08743', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '健康人尿液中除了下列那一項外皆應該是檢測不出的？', '["葡萄糖", "酮體", "血", "蛋白質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "83a391b0e81d", "answer_pdf_sha1": "281d83a8ba65", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
